import React, { useState, useEffect } from 'react';
import axios from 'axios';

const clientId = 'your-client-id';
const redirectUri = encodeURIComponent('http://localhost:3000/callback');
const authorizationEndpoint = 'https://your-auth-server/oauth/authorize';

function Login() {
  const [userProfile, setUserProfile] = useState(null);

  useEffect(() => {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');

    if (code) {
      axios.post('https://your-auth-server/oauth/token', {
        grant_type: 'authorization_code',
        client_id,
        redirect_uri,
        code
      })
      .then(response => {
        localStorage.setItem('id_token', response.data.id_token);
        decodeToken(response.data.id_token);
      })
      .catch(error => {
        console.error('Error exchanging code for tokens:', error);
      });
    }
  }, []);

  const handleLogin = () => {
    window.location.href = `${authorizationEndpoint}?response_type=code&client_id=${clientId}&redirect_uri=${redirectUri}`;
  };

  const decodeToken = (idToken) => {
    try {
      const base64Url = idToken.split('.')[1];
      const decoded = atob(base64Url);
      const userProfile = JSON.parse(decoded);
      setUserProfile(userProfile);
      localStorage.setItem('user_profile', JSON.stringify(userProfile));
    } catch (error) {
      console.error('Error decoding token:', error);
    }
  };

  return (
    <div>
      {userProfile ? (
        <div>Welcome, {userProfile.name}!</div>
      ) : (
        <button onClick={handleLogin}>Log in with OpenID Connect</button>
      )}
    </div>
  );
}

export default Login;